     9→  SerializableOnly,
    10→  UnionToIntersection,
    11→  Writable,
    12→} from '../../helpers/type-utils';
    13→import type { CacheStrategy } from './cache';
    14→import type { MachineAction, MachineStoreMiddlewareAPI, METADATA_FIELD_NAME } from './machine';
    15→import type { AsyncSlice, Slice, SliceKind } from './slice';
    16→
    17→/**
    18→ * Represents the runtime context, which can contain serializable data
    19→ * or functions (e.g., an API client).
    20→ */
    21→export type SliceContext = {
    22→  [K: string]: Serializable | AnyFunction | SliceContext;
    23→} & { userID?: MachineUserID };
    24→
    25→/** Represents the shape of a slice's state. */
    26→export type MachineState = { [K: string]: unknown };
    27→
    28→/**
    29→ * A proxy of the state passed to reducers (via Immer).
    30→ * It allows for direct, "mutable" syntax for state updates.
    31→ */
    32→export type WritableStateProxy<State> = Writable<SerializableOnly<State>>;
    33→
    34→export type MachineReducer<State = MachineState, Action = MachineAction> = (
    35→  state: Readonly<State>,
    36→  action: Action,
    37→) => State;
    38→
    39→export type SliceReducer<State = MachineState, Payload = unknown> = (
    40→  state: WritableStateProxy<State>,
    41→  payload: Payload,
    42→) => void;
    43→
    44→/**
    45→ * @internal
    46→ * Extracts the return types of all selector functions.
    47→ */
    48→export type ExtractSelectorValues<Selectors> = {
    49→  [K in keyof Selectors]: Selectors[K] extends (s: any) => infer R ? R : never;
    50→};
    51→
    52→export type MachineUserID = string | number | null | undefined;
    53→
    54→/**
    55→ * Internal Machine metadata
    56→ */
    57→export type MachineMetadata = {
    58→  userID: MachineUserID; // used to handle the cache policy
    59→  updatedAt: number; // timestamp from last machine state change
    60→  startedAt: number; // defined at the first rootReducer iteration
    61→  updatedByActionType: string; // last action type that updated state
    62→  changes: number; // changes count
    63→  sessionID: string;
    64→  slicesCacheStrategy: {
    65→    [K: string]: CacheStrategy | undefined; // the cache strategy used for each slice
    66→  };
    67→};
    68→
    69→export type WithMetadata<State> = State & {
    70→  [L in METADATA_FIELD_NAME]: MachineMetadata;
    71→};
    72→
    73→export type WithMetadataParam<State> = State & {
    74→  [L in METADATA_FIELD_NAME]?: MachineMetadata;
    75→};
    76→
    77→export type MachineMiddleware = (
    78→  api: MachineStoreMiddlewareAPI,
    79→) => (next: (action: UnknownAction) => UnknownAction) => (action: UnknownAction) => any;
    80→
    81→/**
    82→ * Utility type that merges the contexts from all slices in a machine
    83→ * into a single, unified context type.
    84→ */
    85→export type CombineSlicesContext<Slices> = Compute<
    86→  UnionToIntersection<
    87→    {
    88→      -readonly [K in keyof Slices]: Slices[K] extends { context: infer C } ? C : never;
    89→    }[keyof Slices]
    90→  >
    91→>;
    92→
    93→/**
    94→ * Utility type that combines the initial states of all slices into a single
    95→ * global state object for the machine.
    96→ */
    97→export type CombineSlicesState<Slices> = Cast<
    98→  Compute<
    99→    UnionToIntersection<{
   100→      -readonly [K in keyof Slices]: Slices[K] extends { initial: infer I } ? I : never;
   101→    }>
   102→  >,
   103→  MachineState
   104→>;
   105→
   106→/** A record of slice definitions. */
   107→export type MachineSlices = { [K: string]: AnyMachineSlice };
   108→
   109→/** A record of selector functions. */
   110→export type MachineSelectors<State> = {
   111→  [K: string]: (state: State) => unknown;
   112→};
   113→
   114→export type AnySyncSlice = ComputeAny<Slice<any, any, any> & { kind: SliceKind.sync }>;
   115→export type AnyAsyncSlice = ComputeAny<AsyncSlice<any, any, any, any> & { kind: SliceKind.async }>;
   116→export type AnyMachineSlice = Omit<AnySyncSlice | AnyAsyncSlice, 'context' | 'cache'> & {
   117→  context?: SliceContext;
   118→  cache: CacheStrategy;
   119→};
   120→
   121→/**
   122→ * Infers the complete state shape of a machine, including the
   123→ * return values of its selectors.
   124→ */
   125→export type InferMachineState<MachineConfig> = MachineConfig extends {
   126→  readonly config: {
   127→    slices: infer Slices extends MachineSlices;
   128→    selectors?: infer Selectors;
   129→  };
   130→}
   131→  ? WithSelectorsState<CombineSlicesState<Slices>, Selectors>
   132→  : never;
   133→
   134→/**
   135→ * Extract types from all machine custom selectors config.
   136→ */
   137→export type WithSelectorsState<State, Selectors> = Compute<
   138→  State & {
   139→    +readonly [K in keyof Selectors]: Selectors[K] extends (...args: any) => infer R ? R : never;
   140→  },
   141→  'flat'
   142→>;
   143→
   144→export type UnknownAction = { type: string } & { [K: string]: unknown };
   145→
   146→export type AsyncSliceError = {
   147→  error: string;
   148→  stack: string;
   149→};
   150→
   151→export type AsyncSliceActions<Payload = any, Result = any, Context = any> = {
   152→  load(payload: Payload, context: Context): MachineAction<Payload>;
   153→  fail(payload: AsyncSliceError): MachineAction<AsyncSliceError>;
   154→  success(data: PromiseValue<Result>): MachineAction<Result>;
   155→  clear(): MachineAction<Payload>;
   156→};
   157→
   158→/**
   159→ * Maps a slice definition to its corresponding action creators.
   160→ */
   161→export type SliceToActionCreators<Slice> =
   162→  // Async slice case
   163→  Slice extends {
   164→    load(payload: infer Payload, context: any): infer Result;
   165→  }
   166→    ? {
   167→        load(payload: Payload): MachineAction<Payload>;
   168→        fail(payload: AsyncSliceError): MachineAction<AsyncSliceError>;
   169→        success(data: PromiseValue<Result>): MachineAction<Result>;
   170→        clear(): MachineAction<Payload>;
   171→      }
   172→    : // Sync slice case
   173→      Slice extends { reducers: infer Reducers }
   174→      ? Writable<{
   175→          [K in keyof Reducers]: Reducers[K] extends unknown
   176→            ? Reducers[K] extends (state: any, ...args: [infer Payload] & { length: 1 }) => any
   177→              ? (payload: Payload) => MachineAction<Payload>
   178→              : () => MachineAction<void>
   179→            : never;
   180→        }>
   181→      : never;
   182→
   183→/**
   184→ * Maps a slice definition to its corresponding action type strings.
   185→ * The format is `@<MachineID>/<SliceID>/<ActionName>`.
   186→ */
   187→export type SliceToActionTypes<MachineID extends string, Slice> = // Async slice case
   188→Slice extends {
   189→  id: infer ID extends string;
   190→  load(...args: any): any;
   191→}
   192→  ? {
   193→      load: `@${MachineID}/${ID}/load`;
   194→      fail: `@${MachineID}/${ID}/fail`;
   195→      success: `@${MachineID}/${ID}/success`;
   196→      clear: `@${MachineID}/${ID}/clear`;
   197→    }
   198→  : // Sync slice case
   199→    Slice extends AnySyncSlice
   200→    ? {
   201→        -readonly [K in keyof Slice['reducers']]: `@${MachineID}/${Slice['id']}/${AsString<K>}`;
   202→      }
   203→    : never;
   204→
   205→/**
   206→ * Used for semantic indicating what each string type represent
   207→ */
   208→export namespace StringTypes {
   209→  export type SliceReducerName = string & { '~kind': 'SliceReducerName' };
   210→
   211→  export type SliceKey = string & { '~kind': 'SliceKey' };
   212→
   213→  export type ActionType = string & { '~kind': 'ActionType' };
   214→}
   215→

